import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ArrowLeft, Crown, Trophy, Timer, Star } from 'lucide-react';
import { pharaohs, Pharaoh } from '@/data/pharaohs';
import { EgyptianCard } from '@/components/ui/EgyptianCard';
import { EgyptianButton } from '@/components/ui/EgyptianButton';
import { useGameAudio } from '@/hooks/useGameAudio';
import { useHighScores } from '@/hooks/useHighScores';
import { useToast } from '@/hooks/use-toast';

interface GuessThePharaohGameProps {
  onBack: () => void;
}

export default function GuessThePharaohGame({ onBack }: GuessThePharaohGameProps) {
  const [level, setLevel] = useState(1);
  const [currentPharaoh, setCurrentPharaoh] = useState<Pharaoh | null>(null);
  const [options, setOptions] = useState<string[]>([]);
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [isGameActive, setIsGameActive] = useState(false);
  const [gameOver, setGameOver] = useState(false);
  const { toast } = useToast();
  const { playSound, stopAmbientMusic, startAmbientMusic } = useGameAudio();
  const { addScore } = useHighScores();

  useEffect(() => {
    if (isGameActive && timeLeft > 0) {
      const timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000);
      return () => clearTimeout(timer);
    } else if (isGameActive && timeLeft === 0) {
      endGame();
    }
  }, [timeLeft, isGameActive]);

  const startGame = () => {
    setLevel(1);
    setScore(0);
    setTimeLeft(60);
    setIsGameActive(true);
    setGameOver(false);
    nextLevel(1);
    startAmbientMusic();
  };

  const endGame = () => {
    setIsGameActive(false);
    setGameOver(true);
    stopAmbientMusic();
    addScore({ playerName: 'Historian', score, game: 'guess-the-pharaoh', details: `Reached level ${level}` });
  };

  const nextLevel = (currentLevel: number) => {
    const pharaoh = pharaohs[Math.floor(Math.random() * pharaohs.length)];
    setCurrentPharaoh(pharaoh);

    const correctOption = pharaoh.name;
    let incorrectOptions: string[] = [];

    const numOptions = Math.min(2 + currentLevel, 6);

    while (incorrectOptions.length < numOptions - 1) {
      const randomPharaoh = pharaohs[Math.floor(Math.random() * pharaohs.length)];
      if (randomPharaoh.name !== correctOption && !incorrectOptions.includes(randomPharaoh.name)) {
        incorrectOptions.push(randomPharaoh.name);
      }
    }

    const allOptions = [correctOption, ...incorrectOptions].sort(() => Math.random() - 0.5);
    setOptions(allOptions);
  };

  const handleGuess = (guess: string) => {
    if (guess === currentPharaoh?.name) {
      const points = level * 10;
      setScore(score + points);
      setLevel(level + 1);
      setTimeLeft(timeLeft + 5);
      toast({ title: 'Correct!', description: `+${points} points! On to the next level!` });
      playSound('correct');
      nextLevel(level + 1);
    } else {
      toast({ title: 'Incorrect', description: 'Try again!', variant: 'destructive' });
      setTimeLeft(Math.max(0, timeLeft - 10));
      playSound('wrong');
    }
  };

  const handleReturn = () => {
    stopAmbientMusic();
    onBack();
  }

  return (
    <div className="min-h-screen pt-20 pb-12 px-4 bg-background">
      <div className="max-w-4xl mx-auto">
        <div className="mb-8">
          <button onClick={handleReturn} className="flex items-center gap-2 text-primary hover:text-gold-light transition-colors mb-4 font-body text-lg">
            <ArrowLeft size={20} /> Back to Games
          </button>
          <h1 className="text-4xl md:text-5xl font-display text-gold-gradient mb-4">Guess the Pharaoh</h1>
        </div>

        <EgyptianCard variant="gold" padding="lg">
          {!isGameActive ? (
            <div className="text-center">
                <p className="text-xl text-muted-foreground font-body mb-8">Ready to test your knowledge of Egyptian rulers?</p>
                <EgyptianButton onClick={startGame} size="xl" variant="hero" shimmer>Start Game</EgyptianButton>
            </div>
          ) : gameOver ? (
            <div className="text-center">
                <h2 className="text-3xl font-display text-terracotta mb-4">Game Over!</h2>
                <p className="text-2xl text-foreground font-body mb-2">You reached level {level}</p>
                <p className="text-3xl text-primary font-bold mb-6">Final Score: {score}</p>
                <div className="flex gap-4 justify-center">
                    <EgyptianButton onClick={startGame} size="lg">Play Again</EgyptianButton>
                    <EgyptianButton onClick={handleReturn} size="lg" variant="outline">Back to Games</EgyptianButton>
                </div>
            </div>
          ) : (
            <div>
              <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-2 text-xl"><Crown /> Level {level}</div>
                <div className="flex items-center gap-2 text-xl"><Trophy /> Score: {score}</div>
                <div className="flex items-center gap-2 text-xl"><Timer /> Time: {timeLeft}s</div>
              </div>
              <motion.div
                key={currentPharaoh?.name}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
              >
                <p className="text-lg md:text-xl mb-6 text-center italic">{currentPharaoh?.clue}</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {options.map((option) => (
                    <EgyptianButton
                      key={option}
                      onClick={() => handleGuess(option)}
                      className="w-full h-16 text-lg"
                      variant="outline"
                    >
                      {option}
                    </EgyptianButton>
                  ))}
                </div>
              </motion.div>
            </div>
          )}
        </EgyptianCard>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Trophy, Timer, Star, Lightbulb, SkipForward } from 'lucide-react';
import { EgyptianCard } from '@/components/ui/EgyptianCard';
import { EgyptianButton } from '@/components/ui/EgyptianButton';
import { useGameAudio } from '@/hooks/useGameAudio';
import { useHighScores } from '@/hooks/useHighScores';

interface HieroglyphDecoderGameProps {
  onBack: () => void;
}

interface HieroglyphPuzzle {
  symbols: string[];
  meaning: string;
  hint: string;
  difficulty: 'easy' | 'medium' | 'hard';
}

const puzzles: HieroglyphPuzzle[] = [
  { symbols: ['≡ôç│', '≡ôéï', '≡ô▓'], meaning: 'RA', hint: 'The sun god', difficulty: 'easy' },
  { symbols: ['≡ôàô', '≡ô▓', '≡ô'], meaning: 'MA', hint: 'Mother goddess Isis', difficulty: 'easy' },
  { symbols: ['≡ôا', '≡ôج'], meaning: 'NEB', hint: 'Lord or master', difficulty: 'easy' },
  { symbols: ['≡ôï╣', '≡ôêû', '≡ô'], meaning: 'ANKH', hint: 'Symbol of life', difficulty: 'easy' },
  { symbols: ['≡ôèز', '≡ô', '≡ôؤ'], meaning: 'PTAH', hint: 'Creator god of Memphis', difficulty: 'medium' },
  { symbols: ['≡ôàâ', '≡ôè╡', '≡ô'], meaning: 'HORUS', hint: 'Falcon-headed sky god', difficulty: 'medium' },
  { symbols: ['≡ôçï', '≡ôï┤', '≡ôçï', '≡ôï┤'], meaning: 'ISIS', hint: 'Goddess of magic', difficulty: 'medium' },
  { symbols: ['≡ôص', '≡ôèذ', '≡ôéï'], meaning: 'OSIRIS', hint: 'God of the afterlife', difficulty: 'medium' },
  { symbols: ['≡ôêû', '≡ôّ', '≡ôéï', '≡ô'], meaning: 'NEFERTITI', hint: 'Beautiful queen', difficulty: 'hard' },
  { symbols: ['≡ô', '≡ôà▒', '≡ô', '≡ôï╣'], meaning: 'TUT', hint: 'Young pharaoh', difficulty: 'hard' },
  { symbols: ['≡ôث', '≡ôèز', '≡ôéï', '≡ôçï'], meaning: 'KHEPRI', hint: 'Scarab beetle god', difficulty: 'hard' },
  { symbols: ['≡ôèâ', '≡ô╝', '≡ô'], meaning: 'SEKHMET', hint: 'Lioness goddess of war', difficulty: 'hard' },
  { symbols: ['≡ôçï', '≡ôêû', '≡ôèز', '≡ôà▒'], meaning: 'ANUBIS', hint: 'God of mummification', difficulty: 'medium' },
  { symbols: ['≡ôéï', '≡ôêû', '≡ôèز', '≡ô'], meaning: 'RENPET', hint: 'The word for year', difficulty: 'hard' },
  { symbols: ['≡ôë', '≡ôë╗'], meaning: 'PHARAOH', hint: 'Great House', difficulty: 'hard' },
  { symbols: ['≡ôêù'], meaning: 'NILE', hint: 'The sacred water', difficulty: 'easy' },
  { symbols: ['≡ôï╣', '≡ôج'], meaning: 'LIFE', hint: 'Symbol of breath', difficulty: 'easy' },
  { symbols: ['≡ôè╣'], meaning: 'GOD', hint: 'Divine being', difficulty: 'easy' },
  { symbols: ['≡ôàô', '≡ôéï'], meaning: 'PYRAMID', hint: 'Place of ascension', difficulty: 'medium' },
  { symbols: ['≡ôèâ', '≡ôêآ'], meaning: 'SCRIBE', hint: 'He who writes', difficulty: 'medium' },
  { symbols: ['≡ôï┤', '≡ôâص'], meaning: 'SPHINX', hint: 'Guardian of the plateau', difficulty: 'medium' },
  { symbols: ['≡ôؤ', '≡ô', '≡ôë'], meaning: 'TEMPLE', hint: 'House of the god', difficulty: 'hard' },
];

export function HieroglyphDecoderGame({ onBack }: HieroglyphDecoderGameProps) {
  const [currentPuzzleIndex, setCurrentPuzzleIndex] = useState(0);
  const [userInput, setUserInput] = useState('');
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [timeLeft, setTimeLeft] = useState(120);
  const [showHint, setShowHint] = useState(false);
  const [feedback, setFeedback] = useState<'correct' | 'wrong' | null>(null);
  const [hintsUsed, setHintsUsed] = useState(0);
  const [skipsUsed, setSkipsUsed] = useState(0);
  const [shuffledPuzzles, setShuffledPuzzles] = useState<HieroglyphPuzzle[]>([]);
  const [difficulty, setDifficulty] = useState<'easy' | 'medium' | 'hard'>('medium');
  const [gameOver, setGameOver] = useState(false);
  const { playSound, startAmbientMusic, stopAmbientMusic } = useGameAudio();
  const { addScore } = useHighScores();

  const maxPuzzles = 10;
  const maxHints = 3;
  const maxSkips = 2;

  const initializeGame = useCallback((level: 'easy' | 'medium' | 'hard') => {
    setDifficulty(level);
    let filteredPuzzles = puzzles;
    if (level === 'easy') {
      filteredPuzzles = puzzles.filter(p => p.difficulty === 'easy' || p.difficulty === 'medium');
    } else if (level === 'hard') {
      filteredPuzzles = puzzles.filter(p => p.difficulty === 'medium' || p.difficulty === 'hard');
    }
    const shuffled = [...filteredPuzzles].sort(() => Math.random() - 0.5).slice(0, maxPuzzles);
    setShuffledPuzzles(shuffled);
    setCurrentPuzzleIndex(0);
    setUserInput('');
    setScore(0);
    setStreak(0);
    setTimeLeft(level === 'easy' ? 180 : level === 'medium' ? 120 : 90);
    setShowHint(false);
    setFeedback(null);
    setHintsUsed(0);
    setSkipsUsed(0);
    setIsPlaying(true);
    setGameOver(false);
    playSound('gameStart');
    startAmbientMusic();
  }, []);

  useEffect(() => {
    if (isPlaying && timeLeft > 0 && !gameOver) {
      const timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000);
      if (timeLeft <= 10) playSound('tick');
      return () => clearTimeout(timer);
    } else if (timeLeft === 0 && isPlaying) {
      setGameOver(true);
      setIsPlaying(false);
      stopAmbientMusic();
      playSound('defeat');
    }
  }, [timeLeft, isPlaying, gameOver]);

  const currentPuzzle = shuffledPuzzles[currentPuzzleIndex];

  const checkAnswer = () => {
    if (!currentPuzzle) return;
    const isCorrect = userInput.toUpperCase().trim() === currentPuzzle.meaning;
    setFeedback(isCorrect ? 'correct' : 'wrong');

    let earnedPoints = 0;
    if (isCorrect) {
      playSound('correct');
      if (streak >= 2) playSound('streak');
      const basePoints = currentPuzzle.difficulty === 'easy' ? 50 : currentPuzzle.difficulty === 'medium' ? 100 : 150;
      const streakBonus = streak * 10;
      const hintPenalty = showHint ? 25 : 0;
      earnedPoints = Math.max(10, basePoints + streakBonus - hintPenalty);
      setScore(prev => prev + earnedPoints);
      setStreak(prev => prev + 1);
    } else {
      playSound('wrong');
      setStreak(0);
    }

    setTimeout(() => {
      setFeedback(null);
      setShowHint(false);
      setUserInput('');
      if (currentPuzzleIndex >= shuffledPuzzles.length - 1) {
        setGameOver(true);
        setIsPlaying(false);
        stopAmbientMusic();
        const finalScore = score + earnedPoints;
        playSound(finalScore >= 300 ? 'victory' : 'defeat');
        addScore({ playerName: 'Explorer', score: finalScore, game: 'decoder', difficulty, details: `Best streak: ${isCorrect ? streak + 1 : streak}` });
      } else {
        setCurrentPuzzleIndex(prev => prev + 1);
      }
    }, 1500);
  };

  const useHintAction = () => {
    if (hintsUsed < maxHints) {
      setShowHint(true);
      setHintsUsed(prev => prev + 1);
      playSound('hint');
    }
  };

  const skipPuzzle = () => {
    if (skipsUsed < maxSkips) {
      playSound('click');
      setSkipsUsed(prev => prev + 1);
      setStreak(0);
      setShowHint(false);
      setUserInput('');
      if (currentPuzzleIndex >= shuffledPuzzles.length - 1) {
        setGameOver(true);
        setIsPlaying(false);
        stopAmbientMusic();
      } else {
        setCurrentPuzzleIndex(prev => prev + 1);
      }
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && userInput.trim()) {
      checkAnswer();
    }
  };

  return (
    <div className="min-h-screen pt-20 pb-12 px-4 bg-background">
      <div className="max-w-4xl mx-auto">
        <div className="mb-8">
          <button
            onClick={() => { stopAmbientMusic(); onBack(); }}
            className="flex items-center gap-2 text-primary hover:text-gold-light transition-colors mb-4 font-body text-lg"
          >
            <ArrowLeft size={20} />
            Back to Games
          </button>
          <h1 className="text-4xl md:text-5xl font-display text-gold-gradient mb-4">Hieroglyph Decoder</h1>
          <p className="text-xl text-muted-foreground font-body">Decipher the ancient symbols and unlock their secrets</p>
        </div>

        <EgyptianCard variant="tomb" padding="lg">
          {isPlaying && (
            <div className="flex flex-wrap justify-between items-center mb-6 gap-4">
              <div className="flex items-center gap-2 bg-lapis/50 px-4 py-2 rounded-lg border border-lapis-light/30">
                <Trophy className="text-primary" size={24} />
                <span className="text-xl text-foreground font-body">{score}</span>
              </div>
              <div className="flex items-center gap-2 bg-muted px-4 py-2 rounded-lg border border-border">
                <Star className="text-turquoise" size={24} />
                <span className="text-xl text-foreground font-body">Streak: {streak}≡ا¤ح</span>
              </div>
              <div className="flex items-center gap-2 bg-muted px-4 py-2 rounded-lg border border-border">
                <Timer className={`${timeLeft < 30 ? 'text-terracotta animate-pulse' : 'text-scarab'}`} size={24} />
                <span className="text-xl text-foreground font-body">{timeLeft}s</span>
              </div>
            </div>
          )}

          {!isPlaying && !gameOver ? (
            <div className="text-center py-12">
              <div className="text-8xl mb-6">≡ôé</div>
              <h2 className="text-4xl font-display text-gold-gradient mb-6">Decode the Ancients</h2>
              <p className="text-xl text-muted-foreground font-body mb-4 max-w-2xl mx-auto">
                Look at the hieroglyphs and type what they represent. Use hints wisely and build your streak for bonus points!
              </p>
              <p className="text-lg text-muted-foreground/80 font-body mb-8">{maxHints} hints ظت {maxSkips} skips ظت {maxPuzzles} puzzles</p>
              <div className="grid md:grid-cols-3 gap-6 max-w-3xl mx-auto">
                <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                  <EgyptianButton variant="turquoise" size="xl" onClick={() => initializeGame('easy')} className="w-full h-auto flex-col py-8">
                    <div className="text-4xl mb-2">≡اô£</div>
                    <span className="text-xl">Scribe</span>
                    <span className="text-sm opacity-80">Easy symbols ظت 180s</span>
                  </EgyptianButton>
                </motion.div>
                <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                  <EgyptianButton variant="default" size="xl" onClick={() => initializeGame('medium')} className="w-full h-auto flex-col py-8">
                    <div className="text-4xl mb-2">≡ا║</div>
                    <span className="text-xl">Priest</span>
                    <span className="text-sm opacity-80">Mixed symbols ظت 120s</span>
                  </EgyptianButton>
                </motion.div>
                <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                  <EgyptianButton variant="danger" size="xl" onClick={() => initializeGame('hard')} className="w-full h-auto flex-col py-8">
                    <div className="text-4xl mb-2">≡اّّ</div>
                    <span className="text-xl">Pharaoh</span>
                    <span className="text-sm opacity-80">Hard symbols ظت 90s</span>
                  </EgyptianButton>
                </motion.div>
              </div>
            </div>
          ) : isPlaying && currentPuzzle ? (
            <AnimatePresence mode="wait">
              <motion.div key={currentPuzzleIndex} initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="space-y-8">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-muted-foreground font-body">Puzzle {currentPuzzleIndex + 1} of {shuffledPuzzles.length}</span>
                  <span className={`px-3 py-1 rounded-full text-sm font-body ${currentPuzzle.difficulty === 'easy' ? 'bg-scarab/30 text-scarab' : currentPuzzle.difficulty === 'medium' ? 'bg-primary/30 text-primary' : 'bg-terracotta/30 text-terracotta'}`}>
                    {currentPuzzle.difficulty.toUpperCase()}
                  </span>
                </div>

                <div className="bg-gradient-to-br from-lapis-deep/50 to-obsidian/50 rounded-2xl p-8 border-2 border-gold/30">
                  <div className="flex items-center justify-center gap-4 text-7xl md:text-8xl mb-4">
                    {currentPuzzle.symbols.map((symbol, index) => (
                      <motion.span key={index} initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: index * 0.2 }} className="drop-shadow-lg">
                        {symbol}
                      </motion.span>
                    ))}
                  </div>
                  {showHint && (
                    <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center text-turquoise font-body text-lg mt-4">
                      ≡اْة Hint: {currentPuzzle.hint}
                    </motion.p>
                  )}
                </div>

                <div className="space-y-4">
                  <div className="relative">
                    <input
                      type="text"
                      value={userInput}
                      onChange={(e) => setUserInput(e.target.value)}
                      onKeyPress={handleKeyPress}
                      placeholder="Type your answer..."
                      disabled={feedback !== null}
                      className="w-full px-6 py-4 text-2xl font-display text-center bg-muted border-2 border-border rounded-xl focus:border-primary focus:outline-none transition-colors uppercase tracking-widest"
                      autoFocus
                    />
                    {feedback && (
                      <motion.div initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }}
                        className={`absolute inset-0 flex items-center justify-center rounded-xl ${feedback === 'correct' ? 'bg-scarab/90' : 'bg-terracotta/90'}`}
                      >
                        <span className="text-3xl font-display text-foreground">
                          {feedback === 'correct' ? 'ظ£ذ Correct!' : `ظإî It was: ${currentPuzzle.meaning}`}
                        </span>
                      </motion.div>
                    )}
                  </div>

                  <div className="flex gap-4 justify-center flex-wrap">
                    <EgyptianButton variant="default" size="lg" onClick={checkAnswer} disabled={!userInput.trim() || feedback !== null}>
                      Submit Answer
                    </EgyptianButton>
                    <EgyptianButton variant="turquoise" size="lg" onClick={useHintAction} disabled={showHint || hintsUsed >= maxHints || feedback !== null}>
                      <Lightbulb size={20} /> Hint ({maxHints - hintsUsed})
                    </EgyptianButton>
                    <EgyptianButton variant="lapis" size="lg" onClick={skipPuzzle} disabled={skipsUsed >= maxSkips || feedback !== null}>
                      <SkipForward size={20} /> Skip ({maxSkips - skipsUsed})
                    </EgyptianButton>
                  </div>
                </div>
              </motion.div>
            </AnimatePresence>
          ) : null}

          {gameOver && (
            <motion.div initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }} className="text-center py-12">
              <div className="text-9xl mb-6">{score >= 500 ? '≡اّّ' : score >= 300 ? '≡ا║' : '≡اô£'}</div>
              <h2 className="text-5xl font-display text-gold-gradient mb-4">
                {score >= 500 ? 'Master Decoder!' : score >= 300 ? 'Skilled Scribe!' : 'Keep Practicing!'}
              </h2>
              <div className="space-y-2 mb-8">
                <p className="text-2xl text-foreground font-body">Final Score: {score}</p>
                <p className="text-xl text-muted-foreground font-body">Best Streak: {streak}≡ا¤ح</p>
                <div className="flex items-center justify-center gap-1 mt-4">
                  {[...Array(5)].map((_, i) => (
                    <Star key={i} className={i < Math.min(5, Math.floor(score / 100)) ? 'text-primary fill-primary' : 'text-muted'} size={32} />
                  ))}
                </div>
              </div>
              <div className="flex gap-4 flex-wrap justify-center">
                <EgyptianButton variant="default" size="lg" onClick={() => initializeGame(difficulty)}>Play Again</EgyptianButton>
                <EgyptianButton variant="lapis" size="lg" onClick={() => { stopAmbientMusic(); onBack(); }}>Back to Games</EgyptianButton>
              </div>
            </motion.div>
          )}
        </EgyptianCard>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Trophy, Timer, Star } from 'lucide-react';
import { EgyptianCard } from '@/components/ui/EgyptianCard';
import { EgyptianButton } from '@/components/ui/EgyptianButton';
import { useGameAudio } from '@/hooks/useGameAudio';
import { useHighScores } from '@/hooks/useHighScores';

interface MemoryGameProps {
  onBack: () => void;
}

interface Card {
  id: number;
  symbol: string;
  isFlipped: boolean;
  isMatched: boolean;
}

const symbols = ['≡ôé', '≡ôث', '≡ôâص', '≡ôï╣', '≡ôë¤', '≡ôç│', '≡ôêû', '≡ôàô', '≡ôô', '≡ôèز', '≡ôë╜', '≡ôص'];

export function MemoryGame({ onBack }: MemoryGameProps) {
  const [cards, setCards] = useState<Card[]>([]);
  const [flippedCards, setFlippedCards] = useState<number[]>([]);
  const [moves, setMoves] = useState(0);
  const [matches, setMatches] = useState(0);
  const [timeLeft, setTimeLeft] = useState(120);
  const [isPlaying, setIsPlaying] = useState(false);
  const [gameWon, setGameWon] = useState(false);
  const [difficulty, setDifficulty] = useState<'easy' | 'medium' | 'hard'>('medium');
  const { playSound, startAmbientMusic, stopAmbientMusic } = useGameAudio();
  const { addScore } = useHighScores();

  useEffect(() => {
    if (isPlaying && timeLeft > 0 && !gameWon) {
      const timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000);
      if (timeLeft <= 10) playSound('tick');
      return () => clearTimeout(timer);
    } else if (timeLeft === 0 && isPlaying) {
      setIsPlaying(false);
      stopAmbientMusic();
      playSound('defeat');
    }
  }, [timeLeft, isPlaying, gameWon]);

