                    className="w-full h-auto flex-col py-8"
                  >
                    <div className="text-4xl mb-2">≡اج¤</div>
                    <span className="text-xl">Medium</span>
                    <span className="text-sm opacity-80">8 pairs ظت 120 seconds</span>
                  </EgyptianButton>
                </motion.div>
                <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
                  <EgyptianButton
